/**
 * Lists the different modes on how beaming for a beat should be done.
 */
public enum class BeatBeamingMode(override val value: Int): com.omnifret.gplayer.core.IGPlayerEnum
{
    /**
     * Automatic beaming based on the timing rules.
     */
    Auto(0),
    /**
     * Force a split to the next beat.
     */
    ForceSplitToNext(1),
    /**
     * Force a merge with the next beat.
     */
    ForceMergeWithNext(2),
    /**
     * Force a split to the next beat on the secondary beam.
     */
    ForceSplitOnSecondaryToNext(3);
    companion object : com.omnifret.gplayer.core.IGPlayerEnumCompanion<BeatBeamingMode>{
        public override val values = arrayOf(Auto, ForceSplitToNext, ForceMergeWithNext, ForceSplitOnSecondaryToNext) 
        public override fun fromValue(v:Double): BeatBeamingMode{
            return when(v.toInt()){
                Auto.value -> Auto
                ForceSplitToNext.value -> ForceSplitToNext
                ForceMergeWithNext.value -> ForceMergeWithNext
                ForceSplitOnSecondaryToNext.value -> ForceSplitOnSecondaryToNext
                else -> throw ClassCastException("No enum with value $v found")}
        }
    }
}

